const LF = String.fromCharCode(10);
const SOURCE = "TechCrunch AI";
const out = [];
for (const item of $input.all()) {
  const root = (item.json && item.json.rss) ? item.json.rss : item.json;
  const channel = root && root.channel ? root.channel : null;
  if (!channel || !channel.item) continue;
  let entries = channel.item;
  if (!Array.isArray(entries)) entries = [entries];
  for (const e of entries) {
    if (!e) continue;
    let link = e.link;
    if (link && typeof link === "object") link = link._ || link.href || "";
    out.push({
      json: {
        title: (e.title || "").toString(),
        link: (link || "").toString(),
        pubDate: (e.pubDate || e.pubdate || e.published || "").toString(),
        description: (e.description || e["content:encoded"] || "").toString(),
        source: SOURCE,
      },
    });
  }
}
return out;

