const LF = String.fromCharCode(10);
const items = $input.all();

function stripHtml(s) {
  if (!s) return "";

  let t = String(s);

  t = t.replace(/<[^>]*>/g, " ");
  t = t
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&quot;/g, '"')
    .replace(/&#039;/g, "'")
    .replace(/&#39;/g, "'")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">");

  return t.replace(/\s+/g, " ").trim();
}

function normUrl(u) {
  if (!u) return "";

  let s = String(u).trim().toLowerCase();
  s = s.split("#")[0].split("?")[0];

  return s.replace(/\/$/, "");
}

function normTitleKey(t) {
  if (!t) return "";

  return String(t)
    .toLowerCase()
    .replace(/[^a-z0-9 ]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

const now = Date.now();
const WEEK_MS = 7 * 24 * 60 * 60 * 1000;

let articles = [];

for (const item of items) {
  const data = item.json || {};

  if (!data.title && !data.link) continue;

  const title = String(data.title || "").trim();
  const link = String(data.link || "").trim();

  if (!title && !link) continue;

  let timestamp = null;

  if (data.pubDate) {
    const parsedDate = Date.parse(data.pubDate);

    if (!Number.isNaN(parsedDate)) {
      timestamp = parsedDate;
    }
  }

  articles.push({
    title,
    link,
    pubDate: String(data.pubDate || ""),
    ts: timestamp,
    description: stripHtml(data.description).slice(0, 1200),
    source: String(data.source || "Unknown Source").trim(),
  });
}

// Keep articles from the last seven days.
// Retain undated articles so a missing date does not break the digest.
articles = articles.filter((article) => {
  return article.ts === null || now - article.ts <= WEEK_MS;
});

// Remove duplicates based on normalized URL or title.
const seenUrls = new Set();
const seenTitles = new Set();
const deduped = [];

for (const article of articles) {
  const urlKey = normUrl(article.link);
  const titleKey = normTitleKey(article.title);

  if (urlKey && seenUrls.has(urlKey)) continue;
  if (titleKey && seenTitles.has(titleKey)) continue;

  if (urlKey) seenUrls.add(urlKey);
  if (titleKey) seenTitles.add(titleKey);

  deduped.push(article);
}

// Sort every source newest-first.
deduped.sort((a, b) => {
  const aTime = a.ts === null ? -Infinity : a.ts;
  const bTime = b.ts === null ? -Infinity : b.ts;

  return bTime - aTime;
});

// Group articles by source.
const articlesBySource = new Map();

for (const article of deduped) {
  const sourceKey = article.source || "Unknown Source";

  if (!articlesBySource.has(sourceKey)) {
    articlesBySource.set(sourceKey, []);
  }

  articlesBySource.get(sourceKey).push(article);
}

// Select articles in rounds across sources.
// This prevents one high-volume feed from occupying all 15 positions.
const sourceGroups = [...articlesBySource.values()];
const limited = [];
let sourceIndex = 0;

while (limited.length < 15) {
  let articleAdded = false;

  for (const group of sourceGroups) {
    if (sourceIndex < group.length && limited.length < 15) {
      limited.push(group[sourceIndex]);
      articleAdded = true;
    }
  }

  if (!articleAdded) break;

  sourceIndex++;
}

// Return the balanced selection in newest-first order.
limited.sort((a, b) => {
  const aTime = a.ts === null ? -Infinity : a.ts;
  const bTime = b.ts === null ? -Infinity : b.ts;

  return bTime - aTime;
});

// Create a compact text representation for the OpenAI node.
const lines = [];

for (let i = 0; i < limited.length; i++) {
  const article = limited[i];

  lines.push(`Article ${i + 1}`);
  lines.push(`Title: ${article.title}`);
  lines.push(`Source: ${article.source}`);
  lines.push(`Published: ${article.pubDate || "unknown"}`);
  lines.push(`URL: ${article.link}`);
  lines.push(`Description: ${article.description}`);
  lines.push("");
}

const combined_articles = lines.join(LF);

return [
  {
    json: {
      count: limited.length,
      articles: limited,
      combined_articles,
    },
  },
];

const LF = String.fromCharCode(10);
const item = $input.first();
let payload = null;
try {
  const out = item.json.output;
  if (Array.isArray(out) && out[0] && Array.isArray(out[0].content) && out[0].content[0]) {
    const txt = out[0].content[0].text;
    payload = (typeof txt === "string") ? JSON.parse(txt) : txt;
  } else if (item.json.digest_title) {
    payload = item.json;
  }
} catch (e) {
  payload = null;
}
if (!payload) {
  payload = { digest_title: "AI & Automation Weekly Intelligence Digest", week_of: "", executive_summary: "No digest content could be generated this week.", takeaways: [] };
}

const title = payload.digest_title || "AI & Automation Weekly Intelligence Digest";
const weekOf = payload.week_of || "";
const summary = payload.executive_summary || "";
const takeaways = Array.isArray(payload.takeaways) ? payload.takeaways : [];

const lines = [];
lines.push("*AI & Automation Weekly Intelligence Digest*");
if (weekOf) lines.push("_Week of " + weekOf + "_");
lines.push("");
if (summary) { lines.push(summary); lines.push(""); }
for (let i = 0; i < takeaways.length; i++) {
  const t = takeaways[i] || {};
  const headline = t.headline || "Untitled";
  lines.push((i + 1) + ". *" + headline + "*");
  if (t.summary) lines.push("   " + t.summary);
  if (t.why_it_matters) lines.push("   *Why it matters:* " + t.why_it_matters);
  if (t.source_url) {
    lines.push("   <" + t.source_url + "|" + (t.source_name || "Source") + ">");
  } else if (t.source_name) {
    lines.push("   Source: " + t.source_name);
  }
  lines.push("");
}
lines.push("_This digest was automatically compiled from TechCrunch AI and VentureBeat AI._");

const markdown = lines.join(LF);
return [{ json: { markdown: markdown } }];
